class Solution:
    def numDecodings(self, s):
        MOD = 10 ** 9 + 7
        digits = '123456789'
        def expand(i, memo):
            if i in memo:
                return memo[i]
            if i == len(s):
                return 1
            total = 0
            opts1 = digits if s[i] == '*' else ([s[i]] if s[i] != '0' else [])
            for d in opts1:
                total += expand(i + 1, memo)
            if i + 1 < len(s):
                first_opts = '12' if s[i] == '*' else ([s[i]] if s[i] in '12' else [])
                for a in first_opts:
                    second_opts = '123456789' if s[i + 1] == '*' else [s[i + 1]]
                    for b in second_opts:
                        val = int(a + b)
                        if 10 <= val <= 26:
                            total += expand(i + 2, memo)
            total %= MOD
            memo[i] = total
            return total
        return expand(0, {}) % MOD

