class Solution:
    def numDecodings(self, s):
        MOD = 10 ** 9 + 7
        n = len(s)
        prev2 = 1
        def ways1(ch):
            if ch == '*':
                return 9
            if ch == '0':
                return 0
            return 1
        prev1 = ways1(s[0])
        for i in range(1, n):
            cur = (prev1 * ways1(s[i])) % MOD
            a, b = s[i - 1], s[i]
            if a == '*' and b == '*':
                cur = (cur + 15 * prev2) % MOD
            elif a == '*':
                if b <= '6':
                    cur = (cur + 2 * prev2) % MOD
                else:
                    cur = (cur + prev2) % MOD
            elif b == '*':
                if a == '1':
                    cur = (cur + 9 * prev2) % MOD
                elif a == '2':
                    cur = (cur + 6 * prev2) % MOD
            else:
                val = int(a + b)
                if 10 <= val <= 26:
                    cur = (cur + prev2) % MOD
            prev2 = prev1
            prev1 = cur
        return prev1 % MOD

