var numDecodings = function(s) {
    const MOD = 1000000007n;
    const n = s.length;
    const ways1 = (ch) => ch === '*' ? 9n : (ch === '0' ? 0n : 1n);
    let prev2 = 1n;
    let prev1 = ways1(s[0]);
    for (let i = 1; i < n; i++) {
        let cur = (prev1 * ways1(s[i])) % MOD;
        const a = s[i - 1], b = s[i];
        if (a === '*' && b === '*') {
            cur = (cur + 15n * prev2) % MOD;
        } else if (a === '*') {
            if (b <= '6') cur = (cur + 2n * prev2) % MOD;
            else cur = (cur + prev2) % MOD;
        } else if (b === '*') {
            if (a === '1') cur = (cur + 9n * prev2) % MOD;
            else if (a === '2') cur = (cur + 6n * prev2) % MOD;
        } else {
            const val = parseInt(a + b, 10);
            if (val >= 10 && val <= 26) cur = (cur + prev2) % MOD;
        }
        prev2 = prev1;
        prev1 = cur;
    }
    return Number(prev1 % MOD);
};
